import requests
import json

# RABBITMQ_URL should be in the format "http://username:password@localhost:15672/api/"
RABBITMQ_URL = ""

def create_vhost(name):
    url = f"{RABBITMQ_URL}/vhosts/{name}"
    headers = {"content-type": "application/json"}
    response = requests.put(url, data='', headers=headers)
    
    if not response.ok:
        print(f"Failed to create vhost {name} with status code {response.status_code}: {response.text}")
    else:
        print(f"Successfully created vhost {name}")
        
def create_user(username, password):
    url = f"{RABBITMQ_URL}/users/{username}"
    headers = {"content-type": "application/json"}
    
    data = json.dumps({'password': password, 'tags': ''})
    response = requests.put(url, data=data, headers=headers)
    
